const text = $input.first().json.message;
const pattern = /On\s+\w{3},\s+\w{3}\s+\d{1,2},\s+\d{4}\s+at\s+\d{1,2}:\d{2}\s*[AP]M/;

const split = text.split(pattern);
const mainMessage = split[0].trim();

return { mainMessage };

// Helper: safely parse JSON
function tryParseJSON(str) {
  try { return JSON.parse(str); } catch { return null; }
}

// Helper: extract the text field from various shapes
function getTextFromAnyShape(root) {
  // Common shapes we might see
  const candidates = [
    root?.response?.[0]?.content?.[0]?.text, // when data is under .response
    root?.[0]?.content?.[0]?.text,           // when the whole array is directly stored
    root?.content?.[0]?.text,                // when content is directly under root
    root?.text                               // fallback
  ];
  return candidates.find(v => typeof v === 'string' && v.trim().length) || '';
}

// Helper: extract a JSON object from a string
function extractJsonObject(text) {
  if (!text) return null;

  // 1) Try fenced code block ```json ... ```
  const fenced = text.match(/```json([\s\S]*?)```/i);
  if (fenced && fenced[1]) {
    const parsed = tryParseJSON(fenced[1].trim());
    if (parsed) return parsed;
  }

  // 2) Try the last {...} block in the text (often the ANALYSIS places JSON at the end)
  // Use a greedy "match any" between braces, pick the last occurrence
  const allBlocks = text.match(/\{[^]*\}/g); // [^]* == any char including newlines
  if (allBlocks && allBlocks.length) {
    // pick the last block; trim to reduce leading/trailing noise
    const lastBlock = allBlocks[allBlocks.length - 1].trim();

    // Sometimes there is trailing markdown-like text after closing brace; attempt to clean
    // Remove trailing characters after the last closing brace
    const cleaned = lastBlock.replace(/(\}[^]*$)/, (m) => {
      // keep only up to the first '}' if extra garbage follows
      const idx = m.indexOf('}');
      return m.slice(0, idx + 1);
    });

    const parsed = tryParseJSON(cleaned);
    if (parsed) return parsed;
  }

  return null;
}

// Process each incoming item and merge results back so expressions keep working
return items.map(item => {
  const root = item.json;
  const text = getTextFromAnyShape(root);
  const extracted = extractJsonObject(text);

  // Fallback if nothing parsed
  const result = extracted ?? { status: "Not Interested", start_time: null };

  return {
    json: {
            // keep original fields
      ...result           // add/override with extracted fields
    }
  };
});

