// n8n Code Tool usually passes ONLY one input called "query"
// Sometimes it is accessible as "query" directly (not "input.query")

const raw =
  (typeof query !== "undefined" ? query : "") ||
  (typeof input !== "undefined" && input?.query ? input.query : "");

const inputDate = String(raw).trim();

if (!inputDate) {
  return JSON.stringify({
    error: "Missing query. Pass ISO date like 2026-01-20 in the tool call as query."
  });
}

// must be YYYY-MM-DD
if (!/^\d{4}-\d{2}-\d{2}$/.test(inputDate)) {
  return JSON.stringify({
    error: "Invalid date format. Use YYYY-MM-DD like 2026-01-20"
  });
}

// Use midday UTC to avoid day shifting
const safeDate = new Date(`${inputDate}T12:00:00Z`);

const weekday = new Intl.DateTimeFormat("en-US", {
  weekday: "long",
  timeZone: "America/Denver",
}).format(safeDate);

const formattedDate = new Intl.DateTimeFormat("en-US", {
  month: "long",
  day: "numeric",
  timeZone: "America/Denver",
}).format(safeDate);

return JSON.stringify({
  iso_date: inputDate,
  weekday_name: weekday,
  formatted_date: formattedDate
});
